// Plane settings: серверное хранение настроек Plane по аккаунту (user_id).
// Body: { action, token, plane_url?, workspace_slug?, plane_token?, plane_user_id? }
//   action = 'load' (вернуть настройки) | 'save' (сохранить).
const body = $input.first().json.body || {};
const action = String(body.action || 'load').trim();
if (!['load','save'].includes(action)) {
  return [{ json: { valid: 0, error: 'Неизвестный action' } }];
}
const token = String(body.token || '').trim();
if (!/^[a-f0-9]{64}$/.test(token)) {
  return [{ json: { valid: 0, error: 'unauthorized', auth_required: true } }];
}
const out = { valid: 1, action, token };
if (action === 'save') {
  const url = String(body.plane_url || '').trim().slice(0, 500);
  const slug = String(body.workspace_slug || '').trim().slice(0, 128);
  const tk = String(body.plane_token || '').trim().slice(0, 500);
  const uid = String(body.plane_user_id || '').trim().slice(0, 128);
  if (!url || !slug || !tk) return [{ json: { valid: 0, error: 'Заполните Plane URL, пространство и токен' } }];
  if (!/^https?:\/\//.test(url)) return [{ json: { valid: 0, error: 'URL должен начинаться с http:// или https://' } }];
  if (!/^[a-z0-9_-]{1,64}$/i.test(slug)) return [{ json: { valid: 0, error: 'Недопустимый workspace slug' } }];
  out.s_url = url; out.s_slug = slug; out.s_token = tk; out.s_userId = uid;
}
return [{ json: out }];

