const item = $input.first();
const data = item && item.json ? item.json : null;
const src = $('Валидация').first().json;
if (data && data.error) {
  return [{ json: { token_valid: false, response: 'error', error: 'database_unavailable' } }];
}
if (!data || !data.user_id) {
  return [{ json: { token_valid: false, response: 'error', error: 'unauthorized', auth_required: true } }];
}
return [{ json: { ...src, token_valid: true, user_id: data.user_id } }];

const items = $input.all().map(i => (i && i.json) || {});
const first = items[0] || {};
const action = $('Token result').first().json.action;
if (first.error) {
  return [{ json: { response: 'error', error: String(first.error.message || first.error) } }];
}
if (action === 'save') {
  return [{ json: { response: 'ok', saved: true } }];
}
const row = items.find(i => i && i.plane_url !== undefined) || {};
const has = !!(row.plane_url || row.workspace_slug || row.plane_token);
return [{ json: { response: 'ok', settings: has ? { url: row.plane_url || '', slug: row.workspace_slug || '', token: row.plane_token || '', userId: row.plane_user_id || '' } : null } }];
